/* Evidence: cmem-worked-cmem-uaf-double-free-dangling-5 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 3045; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct generation_slot { int value; unsigned generation; int occupied; };

static int worked_cmem_uaf_double_free_dangling_5(const struct generation_slot *slot, unsigned handle_generation, int *value) {
  if (slot == NULL || value == NULL || !slot->occupied) return 0;
  if (slot->generation != handle_generation) return 0;
  *value = slot->value;
  return 1;
}

int main(void) {
  struct generation_slot slot = { 25, 6u, 1 };
  int value = 0;
  int stale = worked_cmem_uaf_double_free_dangling_5(&slot, 5u, &value);
  int current = worked_cmem_uaf_double_free_dangling_5(&slot, 6u, &value);
  int invariant = !stale && current && value == 25;
  printf("generation value=%d invariant=%d\n", value, invariant);
  return invariant ? 0 : 1;
}

